const workflowStaticData = $getWorkflowStaticData('global');
const now = Date.now();
const lockTimeout = 30 * 60 * 1000;

if (workflowStaticData.isRunning && workflowStaticData.startTime) {
  const elapsed = now - workflowStaticData.startTime;

  if (elapsed < lockTimeout) {
    return [{ 
      json: { 
        skip: true, 
        reason: "The workflow is currently running.",
        runningSince: new Date(workflowStaticData.startTime).toISOString()
      } 
    }];
  } else {
    delete workflowStaticData.isRunning;
    delete workflowStaticData.startTime;
    console.log("检测到超时锁，强制重置");
  }
}

workflowStaticData.isRunning = true;
workflowStaticData.startTime = now;
workflowStaticData.executionId = $execution.id;

return [{ json: { skip: false, message: "The workflow has started to run." } }];

const items = $input.all();

const checkIntervalSeconds = $('Set Global Workflow Settings').item.json.account_check_interval || 86400;

const filteredItems = items.filter(item => {
  const json = item.json;

  const scrapeNewerThan = json.scrape_newer_than;
  const accountCheckedAt = json.account_checked_at;

  if (!scrapeNewerThan || !accountCheckedAt) {
    return true;
  }

  const scrapeTime = new Date(scrapeNewerThan).getTime();
  const checkedTime = new Date(accountCheckedAt).getTime();

  const diffInSeconds = (checkedTime - scrapeTime) / 1000;

  return diffInSeconds >= checkIntervalSeconds;
});

return filteredItems;

