const inputItems = $input.all();

const inputData = inputItems.map(item => item.json);

const totalCount = inputData.length;
const uniqueAccounts = [...new Set(inputData.map(item => item.account))];
const accountCount = uniqueAccounts.length;

const pureSuccessItems = inputData.filter(item => item.status === 'success');
const crawledItems = inputData.filter(item => item.status === 'crawled');
const failedItems = inputData.filter(item => item.status === 'failed');

const pureSuccessCount = pureSuccessItems.length;
const crawledCount = crawledItems.length;
const failCount = failedItems.length;
const effectiveSuccessCount = pureSuccessCount + crawledCount;
const successRate = totalCount > 0 ? ((effectiveSuccessCount / totalCount) * 100).toFixed(1) : '0.0';

const processedTimes = inputData
  .map(item => item.processedAt ? new Date(item.processedAt) : null)
  .filter(t => t !== null)
  .sort((a, b) => a - b);

const startTime = processedTimes.length > 0 ? processedTimes[0] : null;
const endTime = processedTimes.length > 0 ? processedTimes[processedTimes.length - 1] : null;
const durationSec = startTime && endTime ? ((endTime - startTime) / 1000).toFixed(1) : 0;

const accountStats = {};
const statusDetails = {
  success: [],
  crawled: [],
  failed: []
};

const successAccountsMap = new Map();

inputData.forEach(json => {
  const acc = json.account;
  const status = json.status;

  if (!accountStats[acc]) {
    accountStats[acc] = { 
      total: 0, 
      pureSuccess: 0, 
      crawled: 0, 
      failed: 0,
      ids: {
        pureSuccess: [],
        crawled: [],
        failed: []
      }
    };
  }

  accountStats[acc].total++;

  const detailItem = {
    account: acc,
    id: json.id,
    processedAt: json.processedAt,
    checkedAt: json.account_checked_at,
    reason: json.errorReason || ''
  };

  if (status === 'success') {
    accountStats[acc].pureSuccess++;
    accountStats[acc].ids.pureSuccess.push(json.id);
    statusDetails.success.push(detailItem);

    if (json.account_checked_at) {
      successAccountsMap.set(acc, json.account_checked_at);
    }
  } else if (status === 'crawled') {
    accountStats[acc].crawled++;
    accountStats[acc].ids.crawled.push(json.id);
    statusDetails.crawled.push(detailItem);

    if (json.account_checked_at) {
      successAccountsMap.set(acc, json.account_checked_at);
    }
  } else if (status === 'failed') {
    accountStats[acc].failed++;
    accountStats[acc].ids.failed.push(json.id);
    statusDetails.failed.push(detailItem);
  }
});

let report = `📊 Batch Task Processing Report
━━━━━━━━━━━━━━━━━━━━━━━━━━━
📌 Overall Statistics
   👤 Accounts Involved: ${accountCount}
   📦 Total Tasks: ${totalCount}
   ✅ Pure Success: ${pureSuccessCount}
   🔄 Already Crawled: ${crawledCount}
   📊 Effective Success: ${effectiveSuccessCount}
   ❌ Failed: ${failCount}
   📈 Success Rate: ${successRate}%`;

if (startTime && endTime) {
  report += `
   ⏱️  Processing Period: ${startTime.toISOString().replace('T', ' ').substring(0, 19)} ~ ${endTime.toISOString().replace('T', ' ').substring(0, 19)}
   ⏳ Total Duration: ${durationSec} seconds`;
}

report += `

📋 Per-Account Statistics (${accountCount} Accounts)`;

const accounts = Object.entries(accountStats);
accounts.forEach(([account, stats], index) => {
  const accRate = stats.total > 0 ? (((stats.pureSuccess + stats.crawled) / stats.total) * 100).toFixed(0) : 0;
  const isLast = index === accounts.length - 1;
  const prefix = isLast ? '└─' : '├─';
  const childPrefix = isLast ? '   ' : '│  ';

  report += `
   ${prefix} Account: ${account}
   ${childPrefix}├─ Total: ${stats.total}  (Success Rate: ${accRate}%)
   ${childPrefix}├─ Pure Success: ${stats.pureSuccess} 
   ${childPrefix}├─ Already Crawled: ${stats.crawled} 
   ${childPrefix}└─ Failed: ${stats.failed} `;
});

if (statusDetails.success.length > 0) {
  report += `

✅ Pure Success Task Details (${statusDetails.success.length})`;
  statusDetails.success.forEach((item, idx) => {
    report += `
   ${idx + 1}. Account: ${item.account} | ID: ${item.id}
      └─ Processed At: ${item.processedAt || 'N/A'} | Checked At: ${item.checkedAt || 'N/A'}`;
  });
}

if (statusDetails.crawled.length > 0) {
  report += `

📝 Already Crawled Task Details (${statusDetails.crawled.length})`;
  statusDetails.crawled.forEach((item, idx) => {
    report += `
   ${idx + 1}. Account: ${item.account} | ID: ${item.id}`;
    if (item.reason) report += ` | Reason: ${item.reason}`;
    report += `
      └─ Processed At: ${item.processedAt || 'N/A'}`;
  });
}

if (statusDetails.failed.length > 0) {
  report += `

⚠️ Failed Task Details (${statusDetails.failed.length} items)`;
  statusDetails.failed.forEach((item, idx) => {
    report += `
   ${idx + 1}. Account: ${item.account} | ID: ${item.id}
      ├─ Reason: ${item.reason || 'Unknown Error'}
      └─ Processed At: ${item.processedAt || 'N/A'}`;
  });
}

const needUpdates = Array.from(successAccountsMap.entries()).map(([account, checkedAt]) => ({ 
  account,
  account_checked_at: checkedAt 
}));

if (needUpdates.length > 0) {
  report += `

🔄 Accounts Needing Updates (${needUpdates.length} accounts)`;
  needUpdates.forEach((item, idx) => {
    report += `
   ${idx + 1}. ${item.account} (Checked At: ${item.account_checked_at})`;
  });
}

const timeStr = $now.toUTC().toFormat("yyyy-MM-dd'T'HH:mm:ss'Z'");
report += `

━━━━━━━━━━━━━━━━━━━━━━━━━━
⏰ Report Generated At: ${timeStr}`;

return {
    json: {
      reportText: report,
      summary: {
        accountCount: accountCount, 
        uniqueAccounts: uniqueAccounts,
        total: totalCount,
        pureSuccess: pureSuccessCount,
        crawled: crawledCount,
        effectiveSuccess: effectiveSuccessCount,
        failed: failCount,
        successRate: successRate + '%',
        timeRange: startTime && endTime ? {
          start: startTime.toISOString(),
          end: endTime.toISOString(),
          durationSeconds: parseFloat(durationSec)
        } : null
      },
      accountDetails: accountStats,
      statusBreakdown: statusDetails,
      needUpdates: needUpdates,
      rawData: inputData
    }
};

const now = new Date();
const oneDayMs = 24 * 60 * 60 * 1000;

const filteredItems = items.filter(item => {
  const capturedAt = new Date(item.json.captured_at);
  const diffMs = now - capturedAt;

  return diffMs <= oneDayMs;
});

return filteredItems;

const inputData = $input.all();

const jiedian2Ids = inputData[0].json.jiedian2 || [];
const idSet = new Set(jiedian2Ids);

const jiedian1Item = inputData[0].json.jiedian1;

const id = jiedian1Item.id;

if (!idSet.has(id)) {
  return [jiedian1Item];
} else {
  return [{"reel_id":id, "status": "crawled"}];
}

const inputData = items[0].json.data || [];

const filteredItems = inputData.filter(item => {
  return item.source === "processed_result";
});

const uniqueMap = new Map();
for (const item of filteredItems) {
  const key = item.id || `${item.account}_${item.processedAt}`;
  if (!uniqueMap.has(key)) {
    uniqueMap.set(key, item);
  }
}

const result = Array.from(uniqueMap.values()).map(item => ({
  json: item
}));

return result;

const workflowStaticData = $getWorkflowStaticData('global');
delete workflowStaticData.isRunning;
delete workflowStaticData.startTime;
delete workflowStaticData.executionId;
